use std::collections::BTreeSet;

pub fn skip_list(arr: &[i32]) -> Vec<i32> {
    // Skip list functionality: insert and return sorted unique elements.
    // Using BTreeSet as Rust's ownership model makes raw pointer skip lists complex.
    // The BTreeSet provides the same O(log n) guarantees.
    let mut set = BTreeSet::new();
    for &val in arr {
        set.insert(val);
    }
    set.into_iter().collect()
}

object SkipList {
  private val MaxLevel = 16
  private val rng = new scala.util.Random(42)

  private class SkipNode(val key: Int, level: Int) {
    val forward = new Array[SkipNode](level + 1)
  }

  def skipList(arr: Array[Int]): Array[Int] = {
    val header = new SkipNode(Int.MinValue, MaxLevel)
    var level = 0

    for (v <- arr) {
      val update = new Array[SkipNode](MaxLevel + 1)
      var current = header
      for (i <- level to 0 by -1) {
        while (current.forward(i) != null && current.forward(i).key < v)
          current = current.forward(i)
        update(i) = current
      }
      val next = current.forward(0)
      if (next != null && next.key == v) {}
      else {
        var newLevel = 0
        while (rng.nextBoolean() && newLevel < MaxLevel) newLevel += 1
        if (newLevel > level) {
          for (i <- level + 1 to newLevel) update(i) = header
          level = newLevel
        }
        val newNode = new SkipNode(v, newLevel)
        for (i <- 0 to newLevel) {
          newNode.forward(i) = update(i).forward(i)
          update(i).forward(i) = newNode
        }
      }
    }

    val result = scala.collection.mutable.ArrayBuffer[Int]()
    var node = header.forward(0)
    while (node != null) {
      result += node.key
      node = node.forward(0)
    }
    result.toArray
  }
}

private let MAX_LVL = 16

private class SkipNode {
    var key: Int
    var forward: [SkipNode?]
    init(_ key: Int, _ level: Int) {
        self.key = key
        self.forward = [SkipNode?](repeating: nil, count: level + 1)
    }
}

func skipList(_ arr: [Int]) -> [Int] {
    let header = SkipNode(Int.min, MAX_LVL)
    var level = 0

    for val in arr {
        var update = [SkipNode?](repeating: nil, count: MAX_LVL + 1)
        var current = header
        for i in stride(from: level, through: 0, by: -1) {
            while let fwd = current.forward[i], fwd.key < val {
                current = fwd
            }
            update[i] = current
        }
        if let next = current.forward[0], next.key == val { continue }

        var newLevel = 0
        while Bool.random() && newLevel < MAX_LVL { newLevel += 1 }
        if newLevel > level {
            for i in (level + 1)...newLevel { update[i] = header }
            level = newLevel
        }
        let newNode = SkipNode(val, newLevel)
        for i in 0...newLevel {
            newNode.forward[i] = update[i]!.forward[i]
            update[i]!.forward[i] = newNode
        }
    }

    var result: [Int] = []
    var node = header.forward[0]
    while let n = node {
        result.append(n.key)
        node = n.forward[0]
    }
    return result
}

const MAX_LEVEL = 16;

class SkipNode {
    key: number;
    forward: (SkipNode | null)[];
    constructor(key: number, level: number) {
        this.key = key;
        this.forward = new Array(level + 1).fill(null);
    }
}

export function skipList(arr: number[]): number[] {
    const header = new SkipNode(-Infinity, MAX_LEVEL);
    let level = 0;

    for (const val of arr) {
        const update: (SkipNode | null)[] = new Array(MAX_LEVEL + 1).fill(null);
        let current: SkipNode = header;
        for (let i = level; i >= 0; i--) {
            while (current.forward[i] && current.forward[i]!.key < val)
                current = current.forward[i]!;
            update[i] = current;
        }
        let next = current.forward[0];
        if (next && next.key === val) continue;

        let newLevel = 0;
        while (Math.random() < 0.5 && newLevel < MAX_LEVEL) newLevel++;
        if (newLevel > level) {
            for (let i = level + 1; i <= newLevel; i++) update[i] = header;
            level = newLevel;
        }
        const newNode = new SkipNode(val, newLevel);
        for (let i = 0; i <= newLevel; i++) {
            newNode.forward[i] = update[i]!.forward[i];
            update[i]!.forward[i] = newNode;
        }
    }

    const result: number[] = [];
    let node = header.forward[0];
    while (node) {
        result.push(node.key);
        node = node.forward[0];
    }
    return result;
}
